import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { handleDelete } from './module';

describe('handleDelete', () => {
  let mockEvent: Partial<Event>;

  beforeEach(() => {
    mockEvent = {
      preventDefault: vi.fn(),
      stopPropagation: vi.fn(),
    };
  });

  afterEach(() => {
    vi.restoreAllMocks();
  });

  it('should handle happy path when a valid event is provided', () => {
    // Arrange
    const target = document.createElement('button');
    // @ts-ignore
    mockEvent.target = target;

    // Act
    const result = handleDelete(mockEvent as Event);

    // Assert
    expect(mockEvent.preventDefault).toHaveBeenCalledOnce();
    expect(mockEvent.stopPropagation).toHaveBeenCalledOnce();
    // Assuming the function returns undefined on success
    expect(result).toBeUndefined();
  });

  it('should handle edge case when the event target has no associated data-id attribute', () => {
    // Arrange
    const target = document.createElement('div'); // no data-id
    // @ts-ignore
    mockEvent.target = target;

    // Act & Assert
    // The function might throw or simply return; we check that it does not crash
    expect(() => handleDelete(mockEvent as Event)).not.toThrow();
    expect(mockEvent.preventDefault).toHaveBeenCalledOnce();
    expect(mockEvent.stopPropagation).toHaveBeenCalledOnce();
  });

  it('should handle null/empty inputs gracefully', () => {
    // @ts-ignore
    expect(() => handleDelete(null)).not.toThrow();
    // @ts-ignore
    expect(() => handleDelete(undefined)).not.toThrow();
    // @ts-ignore
    expect(() => handleDelete('')).not.toThrow();
    // @ts-ignore
    expect(() => handleDelete(0 as any)).not.toThrow();
  });
});